from flags import enabled
from worker_mode import resolved_mode


def test_shared_parser_normalizes_false_and_true_values():
    name = "CHILI_EXPERIMENTAL_GATE"
    for value in ("0", "false", "NO", "off", ""):
        assert enabled({name: value}, name) is False
    for value in ("1", "TRUE", "yes", "On"):
        assert enabled({name: value}, name) is True


def test_worker_consumes_shared_normalized_contract():
    name = "CHILI_EXPERIMENTAL_GATE"
    assert resolved_mode({name: "0"}) == "stable"
    assert resolved_mode({name: "false"}) == "stable"
    assert resolved_mode({name: "YES"}) == "experimental"
